import{_ as s,o as n,c as t,a2 as a}from"./chunks/framework.il0noOp3.js";const u=JSON.parse('{"title":"Overview: Inventory vs Assessment","description":"Which AzureScout tool do you need — the v1 inventory cmdlet or the v2 CAF/WAF assessment platform? A decision guide with two mini quickstarts.","frontmatter":{"description":"Which AzureScout tool do you need — the v1 inventory cmdlet or the v2 CAF/WAF assessment platform? A decision guide with two mini quickstarts."},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),i={name:"overview.md"};function o(r,e,l,d,h,p){return n(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="overview-inventory-vs-assessment" tabindex="-1">Overview: Inventory vs Assessment <a class="header-anchor" href="#overview-inventory-vs-assessment" aria-label="Permalink to &quot;Overview: Inventory vs Assessment&quot;">​</a></h1><p>AzureScout ships <strong>two</strong> entry points from the same module. They answer different questions, have different defaults, and — for the assessment platform — a different PowerShell version requirement. Read this page first if you&#39;re new to AzureScout.</p><table tabindex="0"><thead><tr><th></th><th><code>Invoke-AzureScout</code> (v1)</th><th><code>Invoke-ScoutAssessment</code> (v2)</th></tr></thead><tbody><tr><td>Answers</td><td>&quot;What&#39;s in my tenant?&quot;</td><td>&quot;How well does my tenant conform to CAF/WAF?&quot;</td></tr><tr><td>Output</td><td>Excel workbook, JSON, Markdown, AsciiDoc, Power BI CSVs — raw inventory</td><td>Scored <code>findings.json</code>, Power BI, HTML, PowerPoint, Excel evidence</td></tr><tr><td><code>-Scope</code> default</td><td><code>ArmOnly</code></td><td><code>All</code></td></tr><tr><td>PowerShell</td><td>5.1+ (Desktop or Core)</td><td><strong>7.0+ only</strong> (<code>#Requires -Version 7.0</code>)</td></tr><tr><td>Read the full guide</td><td><a href="./usage.html">Usage Guide</a></td><td><a href="./assessment.html">Assessment Platform</a></td></tr></tbody></table><h2 id="which-one-do-i-need" tabindex="-1">Which one do I need? <a class="header-anchor" href="#which-one-do-i-need" aria-label="Permalink to &quot;Which one do I need?&quot;">​</a></h2><ul><li><strong>I want a spreadsheet/JSON of every resource in my tenant</strong> → use <code>Invoke-AzureScout</code> (inventory).</li><li><strong>I want a scored gap analysis against Microsoft&#39;s Cloud Adoption Framework / Well-Architected Framework, with a prioritized remediation list</strong> → use <code>Invoke-ScoutAssessment</code> (assessment).</li><li><strong>I want both</strong> → run the inventory first for a full raw dataset, then run an assessment for the scored analysis. They are independent — you don&#39;t need to run one before the other.</li></ul><h2 id="quickstart-inventory-invoke-azurescout" tabindex="-1">Quickstart: Inventory (<code>Invoke-AzureScout</code>) <a class="header-anchor" href="#quickstart-inventory-invoke-azurescout" aria-label="Permalink to &quot;Quickstart: Inventory (\`Invoke-AzureScout\`)&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Install from the PowerShell Gallery</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Install-Module</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Name AzureScout</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Sign in (or reuse an existing Connect-AzAccount session)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Connect-AzAccount</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Run a full ARM inventory (default scope — ARM only, no Entra ID)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-AzureScout</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ARM + Entra ID in one run</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-AzureScout</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope All</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>Runs on PowerShell 5.1+ or 7+. See <a href="./prerequisites.html">Prerequisites</a>, <a href="./usage.html">Usage Guide</a>, and <a href="./category-filtering.html">Category Filtering</a> for targeted scans.</p><h2 id="quickstart-assessment-invoke-scoutassessment" tabindex="-1">Quickstart: Assessment (<code>Invoke-ScoutAssessment</code>) <a class="header-anchor" href="#quickstart-assessment-invoke-scoutassessment" aria-label="Permalink to &quot;Quickstart: Assessment (\`Invoke-ScoutAssessment\`)&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Install from the PowerShell Gallery (same module as inventory)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Install-Module</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Name AzureScout</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Sign in — same authentication as the inventory cmdlet, no separate login</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Connect-AzAccount</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Run a full CAF/WAF landing-zone assessment</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>Requires PowerShell 7.0+</strong> — the assessment platform will not load under Windows PowerShell 5.1. See <a href="./assessment-prerequisites.html">Assessment Prerequisites</a> (additional modules and a <code>.NET SDK</code> requirement for the PowerPoint tier) and <a href="./assessment-permissions.html">Assessment Permissions</a> before your first run.</p><h2 id="both-tools-one-module" tabindex="-1">Both tools, one module <a class="header-anchor" href="#both-tools-one-module" aria-label="Permalink to &quot;Both tools, one module&quot;">​</a></h2><p>Both cmdlets ship in the same <code>AzureScout</code> module and share the same sign-in flow (<code>Connect-AZSCLoginSession</code> under the hood) — see <a href="./authentication.html">Authentication</a>. What differs between them is <em>scope defaults</em>, <em>output shape</em>, and — for the assessment platform — the PowerShell version floor.</p><div class="tip custom-block"><p class="custom-block-title">Next steps</p><ul><li>New to the inventory tool? Start at <a href="./prerequisites.html">Prerequisites &amp; Required Modules</a>.</li><li>New to the assessment platform? Start at <a href="./assessment-prerequisites.html">Assessment Prerequisites</a>.</li></ul></div>`,14)])])}const m=s(i,[["render",o]]);export{u as __pageData,m as default};
